+    }
+    Ok(y1_core_positive(x))
+}
+
+fn domain_error_by_mode(
+    function: &'static str,
+    mode: RuntimeMode,
+    input_summary: String,
+    detail: &'static str,
+) -> Result<f64, SpecialError> {
+    match mode {
+        RuntimeMode::Strict => {
+            record_special_trace(
+                function,
+                mode,
+                "domain_error",
+                input_summary,
+                "returned_nan",
+                "strict domain fallback",
+                false,
+            );
+            Ok(f64::NAN)
+        }
+        RuntimeMode::Hardened => {
+            record_special_trace(
+                function,
+                mode,
+                "domain_error",
+                input_summary,
+                "fail_closed",
+                detail,
+                false,
+            );
+            Err(SpecialError {
+                function,
+                kind: SpecialErrorKind::DomainError,
+                mode,
+                detail,
+            })
+        }
+    }
+}
+
+fn jn_nonnegative(n: u32, x: f64) -> f64 {
+    if x.is_nan() {
+        return f64::NAN;
+    }
+    if x.is_infinite() {
+        return 0.0;
+    }
+    if n == 0 {
+        return j0_core(x);
+    }
+    if n == 1 {
+        return j1_core(x);
+    }
+    if x == 0.0 {
+        return 0.0;
+    }
+
+    let mut j_prev = j0_core(x);
+    let mut j_curr = j1_core(x);
+    for k in 1..n {
+        let next = (2.0 * k as f64 / x) * j_curr - j_prev;
+        j_prev = j_curr;
+        j_curr = next;
+    }
+    j_curr
+}
+
+fn yn_nonnegative(n: u32, x: f64) -> f64 {
+    if n == 0 {
+        return y0_core_positive(x);
+    }
+    if n == 1 {
+        return y1_core_positive(x);
+    }
+
+    let mut y_prev = y0_core_positive(x);
+    let mut y_curr = y1_core_positive(x);
+    for k in 1..n {
+        let next = (2.0 * k as f64 / x) * y_curr - y_prev;
+        y_prev = y_curr;
+        y_curr = next;
+    }
+    y_curr
+}
